#ifndef GQA_RAGGED_PREFILL_CAUSAL_H32_KV4_D128_KERNEL_H_
#define GQA_RAGGED_PREFILL_CAUSAL_H32_KV4_D128_KERNEL_H_

#include <cstdint>
#include <cuda_runtime.h>

#if defined(__CUDACC__)
#include <cuda_bf16.h>
#endif

// Fixed constants from spec
constexpr int kNumQoHeads = 32;
constexpr int kNumKvHeads = 4;
constexpr int kHeadDim    = 128;
constexpr int kGqaRatio   = kNumQoHeads / kNumKvHeads; // 8

void gqa_ragged_prefill_causal_h32_kv4_d128_launch(
    const __nv_bfloat16* q,           // [total_q, 32, 128]
    const __nv_bfloat16* k,           // [total_kv, 4, 128]
    const __nv_bfloat16* v,           // [total_kv, 4, 128]
    const int32_t* qo_indptr,         // [len_indptr] (device)
    const int32_t* kv_indptr,         // [len_indptr] (device)
    int32_t len_indptr,
    int32_t total_q,
    float sm_scale,
    __nv_bfloat16* out,               // [total_q, 32, 128]
    float* lse,                       // [total_q, 32] log2-sum-exp
    cudaStream_t stream);

#endif  // GQA_RAGGED_PREFILL_CAUSAL_H32_KV4_D128_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <stdint.h>
#include <math.h>

#if defined(__CUDA_ARCH__) && (__CUDA_ARCH__ < 800)
#error "This kernel requires SM80+."
#endif

__device__ __forceinline__ float bf16_to_f32(__nv_bfloat16 x) { return __bfloat162float(x); }
__device__ __forceinline__ __nv_bfloat16 f32_to_bf16_rn(float x) { return __float2bfloat16_rn(x); }

__device__ __forceinline__ float warp_sum(float v) {
  v += __shfl_down_sync(0xffffffff, v, 16);
  v += __shfl_down_sync(0xffffffff, v, 8);
  v += __shfl_down_sync(0xffffffff, v, 4);
  v += __shfl_down_sync(0xffffffff, v, 2);
  v += __shfl_down_sync(0xffffffff, v, 1);
  return v;
}

__device__ __forceinline__ float log2_lse_from_ms(float m, float s) {
  // lse_nat = m + log(s); lse_log2 = lse_nat / ln(2)
  constexpr float inv_ln2 = 1.4426950408889634f;
  return (m + logf(s)) * inv_ln2;
}

// Find batch id b such that qo_indptr[b] <= q < qo_indptr[b+1]
__device__ __forceinline__ int find_batch_id(const int32_t* __restrict__ qo_indptr, int len_indptr, int q) {
  // upper_bound(q) - 1
  int l = 0;
  int r = len_indptr; // [0, len_indptr)
  while (l < r) {
    int mid = (l + r) >> 1;
    int32_t val = __ldg(qo_indptr + mid);
    if (val <= q) l = mid + 1;
    else r = mid;
  }
  int b = l - 1;
  if (b < 0) b = 0;
  if (b > len_indptr - 2) b = len_indptr - 2;
  return b;
}

constexpr int kThreads = 256; // 8 warps => 32 heads as 4 heads/warp

__global__ void gqa_ragged_prefill_causal_h32_kv4_d128_kernel(
    const __nv_bfloat16* __restrict__ q,
    const __nv_bfloat16* __restrict__ k,
    const __nv_bfloat16* __restrict__ v,
    const int32_t* __restrict__ qo_indptr,
    const int32_t* __restrict__ kv_indptr,
    int32_t len_indptr,
    int32_t total_q,
    float sm_scale,
    __nv_bfloat16* __restrict__ out,
    float* __restrict__ lse) {

  const int global_q = (int)blockIdx.x;
  if (global_q >= total_q) return;

  const int warp = (int)(threadIdx.x >> 5);  // 0..7
  const int lane = (int)(threadIdx.x & 31);  // 0..31

  const int b = find_batch_id(qo_indptr, len_indptr, global_q);

  const int32_t q_start  = __ldg(qo_indptr + b);
  const int32_t q_end    = __ldg(qo_indptr + b + 1);
  const int32_t kv_start = __ldg(kv_indptr + b);
  const int32_t kv_end   = __ldg(kv_indptr + b + 1);

  if (global_q < q_start || global_q >= q_end) return;

  const int num_q_tokens  = (int)(q_end - q_start);
  const int num_kv_tokens = (int)(kv_end - kv_start);

  // Match reference behavior: if empty, leave output=0 and lse=-inf
  if (num_q_tokens <= 0 || num_kv_tokens <= 0) {
    #pragma unroll
    for (int t = 0; t < 4; ++t) {
      const int h = warp + 8 * t;
      #pragma unroll
      for (int i = 0; i < 4; ++i) {
        const int d = lane + 32 * i;
        out[((int64_t)global_q * kNumQoHeads + h) * kHeadDim + d] = f32_to_bf16_rn(0.f);
      }
      if (lane == 0) lse[(int64_t)global_q * kNumQoHeads + h] = -INFINITY;
    }
    return;
  }

  const int delta = num_kv_tokens - num_q_tokens;
  const int q_pos = (int)(global_q - q_start);

  int kv_max = q_pos + 1 + delta;
  kv_max = (kv_max < 0) ? 0 : kv_max;
  kv_max = (kv_max > num_kv_tokens) ? num_kv_tokens : kv_max;

  // Each warp computes 4 heads: h = warp + 8*t, t=0..3 => 32 heads total.
  #pragma unroll
  for (int t = 0; t < 4; ++t) {
    const int h   = warp + 8 * t;  // 0..31
    const int kvh = h >> 3;        // 0..3 (GQA ratio 8)

    // Load Q: each lane loads 4 elements => 128-dim
    float q_reg[4];
    #pragma unroll
    for (int i = 0; i < 4; ++i) {
      const int d = lane + 32 * i;
      q_reg[i] = bf16_to_f32(q[((int64_t)global_q * kNumQoHeads + h) * kHeadDim + d]);
    }

    float m = -INFINITY;
    float s = 0.0f;
    float o_reg[4] = {0.f, 0.f, 0.f, 0.f};

    // Online softmax over allowed kv range [0, kv_max)
    for (int kv_rel = 0; kv_rel < kv_max; ++kv_rel) {
      const int kv_idx = (int)kv_start + kv_rel;

      float partial = 0.f;
      #pragma unroll
      for (int i = 0; i < 4; ++i) {
        const int d = lane + 32 * i;
        const float kf = bf16_to_f32(k[((int64_t)kv_idx * kNumKvHeads + kvh) * kHeadDim + d]);
        partial = fmaf(q_reg[i], kf, partial);
      }
      const float dot = warp_sum(partial) * sm_scale;

      const float m_new = fmaxf(m, dot);
      const float alpha = __expf(m - m_new);
      const float p     = __expf(dot - m_new);

      #pragma unroll
      for (int i = 0; i < 4; ++i) {
        const int d = lane + 32 * i;
        const float vf = bf16_to_f32(v[((int64_t)kv_idx * kNumKvHeads + kvh) * kHeadDim + d]);
        o_reg[i] = o_reg[i] * alpha + p * vf;
      }
      s = s * alpha + p;
      m = m_new;
    }

    const float inv_s = (s > 0.f) ? (1.0f / s) : 0.f;

    #pragma unroll
    for (int i = 0; i < 4; ++i) {
      const int d = lane + 32 * i;
      out[((int64_t)global_q * kNumQoHeads + h) * kHeadDim + d] = f32_to_bf16_rn(o_reg[i] * inv_s);
    }

    if (lane == 0) {
      lse[(int64_t)global_q * kNumQoHeads + h] = (kv_max > 0) ? log2_lse_from_ms(m, s) : -INFINITY;
    }
  }
}

void gqa_ragged_prefill_causal_h32_kv4_d128_launch(
    const __nv_bfloat16* q,
    const __nv_bfloat16* k,
    const __nv_bfloat16* v,
    const int32_t* qo_indptr,
    const int32_t* kv_indptr,
    int32_t len_indptr,
    int32_t total_q,
    float sm_scale,
    __nv_bfloat16* out,
    float* lse,
    cudaStream_t stream) {

  dim3 block(kThreads, 1, 1);
  dim3 grid((uint32_t)total_q, 1, 1);
  gqa_ragged_prefill_causal_h32_kv4_d128_kernel<<<grid, block, 0, stream>>>(
      q, k, v, qo_indptr, kv_indptr, len_indptr, total_q, sm_scale, out, lse);
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>

#include <cuda_runtime.h>
#include <cmath>
#include <vector>
#include <sstream>
#include <limits>

#include "kernel.h"

#define TORCH_CHECK_CUDA(x) TORCH_CHECK((x).defined() && (x).device().is_cuda(), #x " must be a CUDA tensor")
#define TORCH_CHECK_CONTIGUOUS(x) TORCH_CHECK((x).is_contiguous(), #x " must be contiguous")
#define TORCH_CHECK_DTYPE(x, dt) TORCH_CHECK((x).dtype() == (dt), #x " has wrong dtype")

static inline std::string sizes_str(const torch::Tensor& t) {
  std::ostringstream oss;
  oss << "[";
  for (int i = 0; i < t.dim(); ++i) {
    oss << t.size(i);
    if (i + 1 < t.dim()) oss << ", ";
  }
  oss << "]";
  return oss.str();
}

static inline void check_indptr_tensor_cuda(const torch::Tensor& t, const char* name) {
  TORCH_CHECK(t.defined(), name, " must be defined");
  TORCH_CHECK_CUDA(t);
  TORCH_CHECK_CONTIGUOUS(t);
  TORCH_CHECK_DTYPE(t, torch::kInt32);
  TORCH_CHECK(t.dim() == 1, name, " must be rank-1, got ", sizes_str(t));
  TORCH_CHECK(t.numel() >= 2, name, " length must be >= 2");
}

std::vector<torch::Tensor> run(
    torch::Tensor q,
    torch::Tensor k,
    torch::Tensor v,
    torch::Tensor qo_indptr,
    torch::Tensor kv_indptr,
    c10::optional<double> sm_scale_opt = c10::nullopt) {

  TORCH_CHECK_CUDA(q);
  TORCH_CHECK_CUDA(k);
  TORCH_CHECK_CUDA(v);
  check_indptr_tensor_cuda(qo_indptr, "qo_indptr");
  check_indptr_tensor_cuda(kv_indptr, "kv_indptr");

  TORCH_CHECK_CONTIGUOUS(q);
  TORCH_CHECK_CONTIGUOUS(k);
  TORCH_CHECK_CONTIGUOUS(v);

  TORCH_CHECK_DTYPE(q, torch::kBFloat16);
  TORCH_CHECK_DTYPE(k, torch::kBFloat16);
  TORCH_CHECK_DTYPE(v, torch::kBFloat16);

  TORCH_CHECK(q.dim() == 3, "q must be rank-3 [total_q,32,128], got ", sizes_str(q));
  TORCH_CHECK(k.dim() == 3, "k must be rank-3 [total_kv,4,128], got ", sizes_str(k));
  TORCH_CHECK(v.dim() == 3, "v must be rank-3 [total_kv,4,128], got ", sizes_str(v));

  const int64_t total_q = q.size(0);
  TORCH_CHECK(q.size(1) == kNumQoHeads && q.size(2) == kHeadDim,
              "q shape must be [total_q,32,128], got ", sizes_str(q));
  TORCH_CHECK(k.size(1) == kNumKvHeads && k.size(2) == kHeadDim,
              "k shape must be [total_kv,4,128], got ", sizes_str(k));
  TORCH_CHECK(v.sizes() == k.sizes(),
              "v must have same shape as k, got v=", sizes_str(v), " k=", sizes_str(k));

  TORCH_CHECK(qo_indptr.numel() == kv_indptr.numel(),
              "qo_indptr and kv_indptr must have same length, got ",
              qo_indptr.numel(), " and ", kv_indptr.numel());
  const int32_t len_indptr = (int32_t)qo_indptr.numel();

  // Validate constraints by reading last element (sync acceptable for correctness guard)
  auto qo_last_cpu = qo_indptr.index({len_indptr - 1}).to(torch::kCPU, /*non_blocking=*/false);
  auto kv_last_cpu = kv_indptr.index({len_indptr - 1}).to(torch::kCPU, /*non_blocking=*/false);
  const int32_t qo_last = qo_last_cpu.item<int32_t>();
  const int32_t kv_last = kv_last_cpu.item<int32_t>();

  TORCH_CHECK((int64_t)qo_last == total_q,
              "Constraint violated: total_q == qo_indptr[-1]. total_q=", total_q, " qo_last=", qo_last);
  TORCH_CHECK((int64_t)kv_last == k.size(0),
              "Constraint violated: total_kv == kv_indptr[-1]. total_kv=", k.size(0), " kv_last=", kv_last);

  const double sm_scale_d = sm_scale_opt.has_value()
      ? *sm_scale_opt
      : (1.0 / std::sqrt((double)kHeadDim));
  const float sm_scale = (float)sm_scale_d;

  auto out = torch::zeros({total_q, kNumQoHeads, kHeadDim},
                          torch::TensorOptions().device(q.device()).dtype(torch::kBFloat16));
  auto lse = torch::full({total_q, kNumQoHeads}, -std::numeric_limits<float>::infinity(),
                         torch::TensorOptions().device(q.device()).dtype(torch::kFloat32));

  const __nv_bfloat16* q_ptr = reinterpret_cast<const __nv_bfloat16*>(q.data_ptr<at::BFloat16>());
  const __nv_bfloat16* k_ptr = reinterpret_cast<const __nv_bfloat16*>(k.data_ptr<at::BFloat16>());
  const __nv_bfloat16* v_ptr = reinterpret_cast<const __nv_bfloat16*>(v.data_ptr<at::BFloat16>());

  const int32_t* qo_ptr = qo_indptr.data_ptr<int32_t>();
  const int32_t* kv_ptr = kv_indptr.data_ptr<int32_t>();

  __nv_bfloat16* out_ptr = reinterpret_cast<__nv_bfloat16*>(out.data_ptr<at::BFloat16>());
  float* lse_ptr = lse.data_ptr<float>();

  cudaStream_t stream = at::cuda::getDefaultCUDAStream();

  gqa_ragged_prefill_causal_h32_kv4_d128_launch(
      q_ptr, k_ptr, v_ptr,
      qo_ptr, kv_ptr,
      len_indptr, (int32_t)total_q, sm_scale,
      out_ptr, lse_ptr, stream);

  cudaError_t err = cudaGetLastError();
  TORCH_CHECK(err == cudaSuccess, "CUDA kernel launch failed: ", cudaGetErrorString(err));

  return {out, lse};
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run,
        py::arg("q"),
        py::arg("k"),
        py::arg("v"),
        py::arg("qo_indptr"),
        py::arg("kv_indptr"),
        py::arg("sm_scale") = py::none(),
        "gqa_ragged_prefill_causal_h32_kv4_d128 (CUDA)");
}
